export type Logger = {
  debug: (...args: any[]) => void;
  info: (...args: any[]) => void;
  warn: (...args: any[]) => void;
  error: (...args: any[]) => void;
};

const noop = () => {};

export const createLogger = (redact: boolean | undefined): Logger => {
  const wrap =
    (fn: (...args: any[]) => void) =>
    (...args: any[]) => {
      if (!__DEV__ && redact) {
        const safe = args.map((a) => {
          try {
            if (typeof a === 'string') return a.replace(/[A-Za-z0-9+/=]{16,}/g, '[REDACTED]');
            return a;
          } catch {
            return '[UNSAFE_LOG]';
          }
        });
        fn(...safe);
      } else {
        fn(...args);
      }
    };

  return {
    debug: wrap(console.debug ? console.debug.bind(console) : noop),
    info: wrap(console.info ? console.info.bind(console) : noop),
    warn: wrap(console.warn ? console.warn.bind(console) : noop),
    error: wrap(console.error ? console.error.bind(console) : noop),
  };
};

