import AsyncStorage from '@react-native-async-storage/async-storage';
import * as Keychain from 'react-native-keychain';

export type SecureStorage = {
  set: (key: string, value: string) => Promise<void>;
  get: (key: string) => Promise<string | null>;
  remove: (key: string) => Promise<void>;
};

const NS = 'PAYMENTS_SECURE_';

export const createSecureStorage = (): SecureStorage => {
  const service = (key: string) => `${NS}${key}`;

  return {
    async set(key, value) {
      await Keychain.setGenericPassword('payments', value, {
        service: service(key),
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
        accessControl: undefined,
        securityLevel: Keychain.SECURITY_LEVEL.SECURE_HARDWARE,
      });
    },
    async get(key) {
      const creds = await Keychain.getGenericPassword({ service: service(key) });
      if (!creds) return null;
      return creds.password || null;
    },
    async remove(key) {
      await Keychain.resetGenericPassword({ service: service(key) });
    },
  };
};

export type KVStorage = {
  setJSON: (key: string, value: any) => Promise<void>;
  getJSON: <T = any>(key: string) => Promise<T | null>;
  remove: (key: string) => Promise<void>;
};

export const createKVStorage = (): KVStorage => {
  const prefix = 'PAYMENTS_KV_';
  return {
    async setJSON(key, value) {
      await AsyncStorage.setItem(prefix + key, JSON.stringify(value));
    },
    async getJSON<T>(key: string) {
      const v = await AsyncStorage.getItem(prefix + key);
      if (!v) return null;
      try {
        return JSON.parse(v) as T;
      } catch {
        return null;
      }
    },
    async remove(key) {
      await AsyncStorage.removeItem(prefix + key);
    },
  };
};

