import 'react-native-get-random-values';
import crypto from 'react-native-quick-crypto';

export const sha256Base64 = (input: string): string => {
  const hash = crypto.createHash('sha256').update(input, 'utf8').digest('base64');
  return hash;
};

export const hmacSha256Base64 = (key: string, data: string): string => {
  const mac = crypto.createHmac('sha256', key).update(data, 'utf8').digest('base64');
  return mac;
};

export const randomBytesBase64 = (size: number): string => {
  return crypto.randomBytes(size).toString('base64');
};

