import { hmacSha256Base64 } from './crypto';

export type HttpClientConfig = {
  baseUrl: string;
  getAuthToken?: () => Promise<string | null>;
  getSigningKey?: () => Promise<string | null>; // optional app-side signing for request integrity (best effort)
  userAgent?: string;
};

export type HttpResponse<T> = {
  ok: boolean;
  status: number;
  data?: T;
  error?: { code?: string; message?: string };
};

const toJSONSafe = async (res: Response) => {
  const text = await res.text();
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch {
    return { raw: text };
  }
};

export const createHttpClient = (cfg: HttpClientConfig) => {
  const url = (path: string) => `${cfg.baseUrl.replace(/\/+$/, '')}/${path.replace(/^\/+/, '')}`;

  const request = async <T>(
    method: 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE',
    path: string,
    body?: any
  ): Promise<HttpResponse<T>> => {
    const token = (await cfg.getAuthToken?.()) || null;
    const signingKey = (await cfg.getSigningKey?.()) || null;

    const payload = body == null ? '' : JSON.stringify(body);
    const ts = new Date().toISOString();
    const nonce = `${Math.random().toString(16).slice(2)}${Date.now().toString(16)}`;
    const sigBase = `${method}\n${path}\n${ts}\n${nonce}\n${payload}`;
    const signature = signingKey ? hmacSha256Base64(signingKey, sigBase) : null;

    const headers: Record<string, string> = {
      Accept: 'application/json',
      'Content-Type': 'application/json',
      'X-Req-Timestamp': ts,
      'X-Req-Nonce': nonce,
    };
    if (cfg.userAgent) headers['User-Agent'] = cfg.userAgent;
    if (token) headers.Authorization = `Bearer ${token}`;
    if (signature) headers['X-Req-Signature'] = signature;

    let res: Response;
    try {
      res = await fetch(url(path), {
        method,
        headers,
        body: body == null ? undefined : payload,
      });
    } catch (e: any) {
      return { ok: false, status: 0, error: { code: 'NETWORK_ERROR', message: e?.message || 'Network error' } };
    }

    const data = await toJSONSafe(res);
    if (res.ok) return { ok: true, status: res.status, data: data as T };

    const code = (data && (data.code || data.errorCode)) || 'HTTP_ERROR';
    const message = (data && (data.message || data.errorMessage)) || `Request failed (${res.status})`;
    return { ok: false, status: res.status, error: { code, message } };
  };

  return {
    get: <T>(path: string) => request<T>('GET', path),
    post: <T>(path: string, body?: any) => request<T>('POST', path, body),
    put: <T>(path: string, body?: any) => request<T>('PUT', path, body),
    patch: <T>(path: string, body?: any) => request<T>('PATCH', path, body),
    del: <T>(path: string) => request<T>('DELETE', path),
  };
};

