import type { PaymentEvent, Unsubscribe } from './types';

export type EventHandler = (event: PaymentEvent) => void;

export const createEventBus = () => {
  const handlers = new Set<EventHandler>();

  return {
    emit(event: PaymentEvent) {
      handlers.forEach((h) => {
        try {
          h(event);
        } catch {}
      });
    },
    on(handler: EventHandler): Unsubscribe {
      handlers.add(handler);
      return () => handlers.delete(handler);
    },
    clear() {
      handlers.clear();
    },
  };
};

