import * as RNIap from 'react-native-iap';
import { Platform } from 'react-native';
import type { IAPProduct, IAPPurchaseReceipt, PurchaseResult } from './types';

export type IAPConfig = {
  android: {
    productIds: string[];
    subscriptionIds?: string[];
  };
  ios: {
    productIds: string[];
    subscriptionIds?: string[];
  };
};

export type IAPController = {
  init: () => Promise<void>;
  end: () => Promise<void>;
  getProducts: () => Promise<IAPProduct[]>;
  requestPurchase: (productId: string) => Promise<PurchaseResult>;
  requestSubscription: (productId: string) => Promise<PurchaseResult>;
  finishTransaction: (receipt: IAPPurchaseReceipt, isConsumable?: boolean) => Promise<void>;
  flushPendingAndroidPurchases: () => Promise<void>;
  onPurchaseUpdated: (cb: (receipt: IAPPurchaseReceipt) => void) => () => void;
  onPurchaseError: (cb: (code: string, message: string) => void) => () => void;
};

const toIAPProduct = (p: any, type: 'inapp' | 'subs'): IAPProduct => ({
  productId: p.productId,
  title: p.title,
  description: p.description,
  localizedPrice: p.localizedPrice,
  price: p.price,
  currency: p.currency,
  type,
});

const purchaseToReceipt = (purchase: any): IAPPurchaseReceipt => {
  const platform = Platform.OS === 'ios' ? 'ios' : 'android';
  return {
    transactionId: purchase.transactionId,
    productId: purchase.productId,
    purchaseToken: purchase.purchaseToken,
    transactionReceipt: purchase.transactionReceipt,
    originalTransactionId: purchase.originalTransactionIdentifierIOS,
    platform,
    raw: purchase,
  };
};

export const createIAPController = (cfg: IAPConfig): IAPController => {
  let purchaseUpdateSub: any = null;
  let purchaseErrorSub: any = null;

  const ids = () => {
    if (Platform.OS === 'ios') {
      return {
        products: cfg.ios.productIds || [],
        subs: cfg.ios.subscriptionIds || [],
      };
    }
    return {
      products: cfg.android.productIds || [],
      subs: cfg.android.subscriptionIds || [],
    };
  };

  return {
    async init() {
      await RNIap.initConnection();
      if (Platform.OS === 'android') {
        await RNIap.flushFailedPurchasesCachedAsPendingAndroid?.();
      }
    },

    async end() {
      purchaseUpdateSub?.remove?.();
      purchaseErrorSub?.remove?.();
      purchaseUpdateSub = null;
      purchaseErrorSub = null;
      try {
        await RNIap.endConnection();
      } catch {}
    },

    async getProducts() {
      const { products, subs } = ids();
      const out: IAPProduct[] = [];
      if (products.length) {
        const ps = await RNIap.getProducts({ skus: products } as any);
        out.push(...ps.map((p: any) => toIAPProduct(p, 'inapp')));
      }
      if (subs.length) {
        const ss = await RNIap.getSubscriptions({ skus: subs } as any);
        out.push(...ss.map((p: any) => toIAPProduct(p, 'subs')));
      }
      return out;
    },

    async requestPurchase(productId) {
      try {
        const purchase = await RNIap.requestPurchase({ sku: productId } as any);
        const receipt = Array.isArray(purchase) ? purchaseToReceipt(purchase[0]) : purchaseToReceipt(purchase);
        return { ok: true, provider: Platform.OS === 'ios' ? 'APPLE_IAP' : 'GOOGLE_IAP', receipt };
      } catch (e: any) {
        return {
          ok: false,
          provider: Platform.OS === 'ios' ? 'APPLE_IAP' : 'GOOGLE_IAP',
          errorCode: e?.code || 'IAP_PURCHASE_FAILED',
          errorMessage: e?.message || 'Purchase failed',
        };
      }
    },

    async requestSubscription(productId) {
      try {
        const purchase = await RNIap.requestSubscription({ sku: productId } as any);
        const receipt = Array.isArray(purchase) ? purchaseToReceipt(purchase[0]) : purchaseToReceipt(purchase);
        return { ok: true, provider: Platform.OS === 'ios' ? 'APPLE_IAP' : 'GOOGLE_IAP', receipt };
      } catch (e: any) {
        return {
          ok: false,
          provider: Platform.OS === 'ios' ? 'APPLE_IAP' : 'GOOGLE_IAP',
          errorCode: e?.code || 'IAP_SUBSCRIPTION_FAILED',
          errorMessage: e?.message || 'Subscription failed',
        };
      }
    },

    async finishTransaction(receipt, isConsumable) {
      const p = receipt.raw;
      await RNIap.finishTransaction({ purchase: p, isConsumable: !!isConsumable } as any);
    },

    async flushPendingAndroidPurchases() {
      if (Platform.OS !== 'android') return;
      await RNIap.flushFailedPurchasesCachedAsPendingAndroid?.();
    },

    onPurchaseUpdated(cb) {
      purchaseUpdateSub?.remove?.();
      purchaseUpdateSub = RNIap.purchaseUpdatedListener((purchase: any) => cb(purchaseToReceipt(purchase)));
      return () => purchaseUpdateSub?.remove?.();
    },

    onPurchaseError(cb) {
      purchaseErrorSub?.remove?.();
      purchaseErrorSub = RNIap.purchaseErrorListener((e: any) => cb(e?.code || 'IAP_ERROR', e?.message || 'IAP error'));
      return () => purchaseErrorSub?.remove?.();
    },
  };
};

