import type { WalletBalance, WalletInit, WalletOperationResult, WalletTransaction, Money } from './types';
import type { Logger } from './logger';
import type { SecureStorage } from './storage';
import type { ReturnTypeHttpClient } from './walletHttpTypes';

export type WalletHttp = ReturnTypeHttpClient;

export type WalletController = {
  init: (init: WalletInit) => Promise<WalletOperationResult<{ walletId: string }>>;
  getBalance: () => Promise<WalletOperationResult<WalletBalance>>;
  listTransactions: (params?: { limit?: number; cursor?: string }) => Promise<WalletOperationResult<{ items: WalletTransaction[]; nextCursor?: string }>>;
  createTransaction: (input: { type: WalletTransaction['type']; money: Money; metadata?: Record<string, string> }) => Promise<WalletOperationResult<WalletTransaction>>;
  setSessionToken: (token: string | null) => Promise<void>;
  getSessionToken: () => Promise<string | null>;
  clear: () => Promise<void>;
};

export type WalletState = {
  walletId: string | null;
  customerId: string | null;
};

export const createWalletController = (deps: {
  http: WalletHttp;
  secure: SecureStorage;
  logger: Logger;
}) => {
  const TOKEN_KEY = 'wallet_session_token';
  const STATE_KEY = 'wallet_state';

  const getState = async (): Promise<WalletState> => {
    const raw = await deps.secure.get(STATE_KEY);
    if (!raw) return { walletId: null, customerId: null };
    try {
      const p = JSON.parse(raw);
      return { walletId: p.walletId ?? null, customerId: p.customerId ?? null };
    } catch {
      return { walletId: null, customerId: null };
    }
  };

  const setState = async (s: WalletState) => {
    await deps.secure.set(STATE_KEY, JSON.stringify(s));
  };

  const controller: WalletController = {
    async init(init) {
      const res = await deps.http.post<{ walletId: string }>('/wallet/init', init);
      if (!res.ok) {
        return { ok: false, errorCode: res.error?.code, errorMessage: res.error?.message };
      }
      await setState({ walletId: res.data!.walletId, customerId: init.customerId });
      return { ok: true, data: res.data! };
    },

    async getBalance() {
      const s = await getState();
      if (!s.walletId) return { ok: false, errorCode: 'NO_WALLET', errorMessage: 'Wallet not initialized' };
      const res = await deps.http.get<WalletBalance>(`/wallet/${encodeURIComponent(s.walletId)}/balance`);
      if (!res.ok) return { ok: false, errorCode: res.error?.code, errorMessage: res.error?.message };
      return { ok: true, data: res.data! };
    },

    async listTransactions(params) {
      const s = await getState();
      if (!s.walletId) return { ok: false, errorCode: 'NO_WALLET', errorMessage: 'Wallet not initialized' };
      const qs = new URLSearchParams();
      if (params?.limit != null) qs.set('limit', String(params.limit));
      if (params?.cursor) qs.set('cursor', params.cursor);
      const path = `/wallet/${encodeURIComponent(s.walletId)}/transactions${qs.toString() ? `?${qs.toString()}` : ''}`;
      const res = await deps.http.get<{ items: WalletTransaction[]; nextCursor?: string }>(path);
      if (!res.ok) return { ok: false, errorCode: res.error?.code, errorMessage: res.error?.message };
      return { ok: true, data: res.data! };
    },

    async createTransaction(input) {
      const s = await getState();
      if (!s.walletId) return { ok: false, errorCode: 'NO_WALLET', errorMessage: 'Wallet not initialized' };
      const res = await deps.http.post<WalletTransaction>(`/wallet/${encodeURIComponent(s.walletId)}/transactions`, input);
      if (!res.ok) return { ok: false, errorCode: res.error?.code, errorMessage: res.error?.message };
      return { ok: true, data: res.data! };
    },

    async setSessionToken(token) {
      if (!token) {
        await deps.secure.remove(TOKEN_KEY);
        return;
      }
      await deps.secure.set(TOKEN_KEY, token);
    },

    async getSessionToken() {
      return await deps.secure.get(TOKEN_KEY);
    },

    async clear() {
      await deps.secure.remove(TOKEN_KEY);
      await deps.secure.remove(STATE_KEY);
    },
  };

  return controller;
};

