import { Platform } from 'react-native';
import DeviceInfo from 'react-native-device-info';
import { v4 as uuidv4 } from 'uuid';

import type { PaymentModuleConfig, PaymentEvent, IAPPurchaseReceipt, PurchaseResult, IAPProduct } from './types';
import { createLogger } from './logger';
import { createSecureStorage, createKVStorage } from './storage';
import { createHttpClient } from './http';
import { createEventBus } from './events';
import { createIAPController, type IAPConfig } from './iap';
import { createWalletController } from './wallet';

export type PaymentModule = {
  configure: (cfg: PaymentModuleConfig) => void;
  init: (opts: { iap: IAPConfig; userAuthTokenProvider?: () => Promise<string | null> }) => Promise<void>;
  end: () => Promise<void>;

  onEvent: (handler: (e: PaymentEvent) => void) => () => void;

  iap: {
    getProducts: () => Promise<IAPProduct[]>;
    purchaseProduct: (productId: string, opts?: { isConsumable?: boolean; validateWithBackend?: boolean }) => Promise<PurchaseResult>;
    subscribe: (productId: string, opts?: { validateWithBackend?: boolean }) => Promise<PurchaseResult>;
    restorePurchases: () => Promise<IAPPurchaseReceipt[]>;
  };

  wallet: ReturnType<typeof createWalletController>;

  security: {
    rotateClientSigningKey: () => Promise<void>;
    getClientSigningKeyId: () => Promise<string | null>;
  };
};

export const createPaymentModule = (): PaymentModule => {
  const secure = createSecureStorage();
  const kv = createKVStorage();
  let config: PaymentModuleConfig | null = null;

  const bus = createEventBus();
  const logger = createLogger(true);

  const SIGNING_KEY_ID = 'client_signing_key_id';
  const SIGNING_KEY = 'client_signing_key';

  const getSigningKey = async () => await secure.get(SIGNING_KEY);

  const rotateClientSigningKey = async () => {
    const keyId = uuidv4();
    const key = uuidv4().replace(/-/g, '') + uuidv4().replace(/-/g, '');
    await secure.set(SIGNING_KEY_ID, keyId);
    await secure.set(SIGNING_KEY, key);
  };

  const getClientSigningKeyId = async () => await secure.get(SIGNING_KEY_ID);

  let http: ReturnType<typeof createHttpClient> | null = null;
  let iapCtrl: ReturnType<typeof createIAPController> | null = null;

  const wallet = createWalletController({
    get http() {
      if (!http) throw new Error('Payment module not initialized');
      return http as any;
    },
    secure,
    logger,
  } as any);

  const validateReceiptWithBackend = async (receipt: IAPPurchaseReceipt) => {
    if (!http || !config?.provider.apiBaseUrl) return { ok: true };
    const device = {
      deviceId: await DeviceInfo.getUniqueId(),
      systemName: DeviceInfo.getSystemName(),
      systemVersion: DeviceInfo.getSystemVersion(),
      brand: DeviceInfo.getBrand(),
      model: DeviceInfo.getModel(),
      appVersion: DeviceInfo.getVersion(),
      buildNumber: DeviceInfo.getBuildNumber(),
      platform: Platform.OS,
    };

    const res = await http.post<{ valid: boolean; reason?: string }>('/iap/validate', {
      receipt,
      device,
      keyId: await getClientSigningKeyId(),
    });

    if (!res.ok) return { ok: false as const, errorCode: res.error?.code, errorMessage: res.error?.message };
    if (!res.data?.valid) return { ok: false as const, errorCode: 'RECEIPT_INVALID', errorMessage: res.data?.reason || 'Receipt invalid' };
    return { ok: true as const };
  };

  const restorePurchases = async (): Promise<IAPPurchaseReceipt[]> => {
    if (!iapCtrl) throw new Error('IAP not initialized');
    const purchases = await (require('react-native-iap') as typeof import('react-native-iap')).getAvailablePurchases();
    return purchases.map((p: any) => ({
      transactionId: p.transactionId,
      productId: p.productId,
      purchaseToken: p.purchaseToken,
      transactionReceipt: p.transactionReceipt,
      originalTransactionId: p.originalTransactionIdentifierIOS,
      platform: Platform.OS === 'ios' ? 'ios' : 'android',
      raw: p,
    }));
  };

  return {
    configure(cfg) {
      config = cfg;
    },

    async init(opts) {
      if (!config) {
        config = {
          provider: {
            env: __DEV__ ? 'sandbox' : 'production',
          },
          security: { redactLogs: true },
        };
      }

      const redact = config.security?.redactLogs ?? true;
      (logger as any).debug = createLogger(redact).debug;
      (logger as any).info = createLogger(redact).info;
      (logger as any).warn = createLogger(redact).warn;
      (logger as any).error = createLogger(redact).error;

      if (!(await getClientSigningKeyId()) || !(await getSigningKey())) {
        await rotateClientSigningKey();
      }

      const apiBaseUrl = config.provider.apiBaseUrl;
      if (apiBaseUrl) {
        http = createHttpClient({
          baseUrl: apiBaseUrl,
          getAuthToken: async () => (await opts.userAuthTokenProvider?.()) || (await wallet.getSessionToken()),
          getSigningKey,
          userAgent: `PaymentsModule/${DeviceInfo.getVersion()} (${Platform.OS})`,
        });
      } else {
        http = createHttpClient({
          baseUrl: 'http://127.0.0.1',
          getAuthToken: async () => (await opts.userAuthTokenProvider?.()) || (await wallet.getSessionToken()),
          getSigningKey,
          userAgent: `PaymentsModule/${DeviceInfo.getVersion()} (${Platform.OS})`,
        });
      }

      iapCtrl = createIAPController(opts.iap);
      await iapCtrl.init();
      bus.emit({ type: 'iap:connected' });

      iapCtrl.onPurchaseUpdated((r) => bus.emit({ type: 'iap:purchase-updated', receipt: r }));
      iapCtrl.onPurchaseError((code, message) => bus.emit({ type: 'iap:purchase-error', code, message }));
    },

    async end() {
      try {
        await iapCtrl?.end();
      } finally {
        iapCtrl = null;
        bus.emit({ type: 'iap:disconnected' });
      }
    },

    onEvent(handler) {
      return bus.on(handler);
    },

    iap: {
      async getProducts() {
        if (!iapCtrl) throw new Error('IAP not initialized');
        return await iapCtrl.getProducts();
      },

      async purchaseProduct(productId, opts) {
        if (!iapCtrl) throw new Error('IAP not initialized');
        const res = await iapCtrl.requestPurchase(productId);
        if (!res.ok || !res.receipt) return res;

        if (opts?.validateWithBackend) {
          const v = await validateReceiptWithBackend(res.receipt);
          if (!v.ok) return { ok: false, provider: res.provider, errorCode: v.errorCode, errorMessage: v.errorMessage };
        }

        try {
          await iapCtrl.finishTransaction(res.receipt, opts?.isConsumable);
        } catch (e: any) {
          return {
            ok: false,
            provider: res.provider,
            receipt: res.receipt,
            errorCode: 'FINISH_TX_FAILED',
            errorMessage: e?.message || 'Failed to finalize transaction',
          };
        }

        return res;
      },

      async subscribe(productId, opts) {
        if (!iapCtrl) throw new Error('IAP not initialized');
        const res = await iapCtrl.requestSubscription(productId);
        if (!res.ok || !res.receipt) return res;

        if (opts?.validateWithBackend) {
          const v = await validateReceiptWithBackend(res.receipt);
          if (!v.ok) return { ok: false, provider: res.provider, errorCode: v.errorCode, errorMessage: v.errorMessage };
        }

        try {
          await iapCtrl.finishTransaction(res.receipt, false);
        } catch (e: any) {
          return {
            ok: false,
            provider: res.provider,
            receipt: res.receipt,
            errorCode: 'FINISH_TX_FAILED',
            errorMessage: e?.message || 'Failed to finalize transaction',
          };
        }
        return res;
      },

      async restorePurchases() {
        const receipts = await restorePurchases();
        await kv.setJSON('iap_restore_cache', { at: new Date().toISOString(), receiptsCount: receipts.length });
        return receipts;
      },
    },

    wallet,

    security: {
      rotateClientSigningKey,
      getClientSigningKeyId,
    },
  };
};

