export * from './types';
export * from './paymentModule';

//////////////////////////////
// Example usage: AppPayments.ts
//////////////////////////////
import { createPaymentModule } from './payments';

export const Payments = createPaymentModule();

export const initPayments = async (userAuthTokenProvider?: () => Promise<string | null>) => {
  Payments.configure({
    provider: {
      env: __DEV__ ? 'sandbox' : 'production',
      apiBaseUrl: 'https://api.yourdomain.com',
      telemetryEnabled: false,
    },
    security: {
      redactLogs: true,
      allowEmulator: false,
      requireDeviceIntegrity: false,
    },
  });

  await Payments.init({
    userAuthTokenProvider,
    iap: {
      ios: {
        productIds: ['coins_100', 'coins_500'],
        subscriptionIds: ['pro_monthly'],
      },
      android: {
        productIds: ['coins_100', 'coins_500'],
        subscriptionIds: ['pro_monthly'],
      },
    },
  });
};